fn balance_of_token(token: ContractAddress, owner: ContractAddress) -> u256 {
    let calldata = array![owner.into()];
    let mut result = starknet::call_contract_syscall(token, SELECTOR_balanceOf, calldata.span());
    if result.is_err() {
        result = starknet::call_contract_syscall(token, SELECTOR_BALANCEOF, calldata.span());
    }
    deserialize_u256(result.unwrap_syscall())
}

fn execute_calls(mut calls: Span<Call>) -> Array<Span<felt252>> {
    let mut res = array![];
    for call in calls {
        let Call { to, selector, calldata } = *call;
        res.append(starknet::syscalls::call_contract_syscall(to, selector, calldata).unwrap_syscall());
    };
    res
}

fn transfer_token(token: ContractAddress, to: ContractAddress, amount: u256) {
    let calldata = array![to.into(), amount.low.into(), amount.high.into()];
    let mut result = starknet::call_contract_syscall(token, SELECTOR_transferFrom, calldata.span());
    if result.is_err() {
        result = starknet::call_contract_syscall(token, SELECTOR_TRANSFERFROM, calldata.span());
    }
    let _ = result.unwrap_syscall();
}

